head.script:
//-------------------------------------------------------------------------
// 화면 - $Id: ar_108_01_01b.xml
// 설명 - Correction Notice 
//-------------------------------------------------------------------------
const loginDTO = $c.data.getMemInfo(); // 전체 로그인 정보
scwin.userId = loginDTO.userId ?? ""; // 사용자 ID

scwin.strCurDate = $c.date.getServerDateTime("yyyyMMdd");
scwin.strPreDate = $c.date.addMonth(scwin.strCurDate, -1);

scwin.seaair = ""; // 해운 항공 구분
scwin.iogb = ""; // Export / Import 구분
scwin.ccaNo = ""; // CCA NO

scwin.processFlag = "";
scwin.mhno = "";
scwin.gubun = "";
scwin.hid_kcomcd = "DBEX";
scwin.hid_mhno = "";
scwin.hid_seaair = "";
scwin.hid_iogb = "";

//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function () {
    // URL 파라미터
    // 올바른 파싱 방법
    var params = $c.data.getParameter();
    scwin.seaair = params?.menuInfo?.menuParam?.seaair || "";
    scwin.iogb = params?.menuInfo?.menuParam?.iogb || "";
    scwin.ccaNo = $c.data.getParameter("ccaNo") || "";

    scwin.hid_kcomcd = "DBEX";
    scwin.hid_seaair = scwin.seaair || "";
    scwin.hid_iogb = scwin.iogb || "";

    // DataMap에 직접 세팅
    dma_search.set("kcomcd", scwin.hid_kcomcd);
    dma_bl_search.set("kcomcd", scwin.hid_kcomcd);
};

scwin.onUdcCompleted = function () {
    setTimeout(function () {
        scwin.f_Set("INIT");
        scwin.f_DefaultValue();
        scwin.processFlag = "INIT";

        scwin.f_initSetTab();
        cnd_ed_ccano.focus();
        // ccaNo가 있으면 자동 조회
        if (scwin.ccaNo !== "") {
            scwin.f_Retrieve();
        }
    }, 0);
}

scwin.cfViewTab = function (tabIndex) {
    tab_main.setSelectedTabIndex(tabIndex);
}

//---------------------------------------------------------
// tab 초기화
//---------------------------------------------------------
scwin.f_initSetTab = function () {
    scwin.cfViewTab(0);
};

//---------------------------------------------------------
// Tab Menu 선택시 처리
//---------------------------------------------------------
scwin.f_selectTabMenu = function (idx) {
    switch (idx) {
        case 0: // Header tab
            break;
        case 1: // Container tab
            break;
    }
};

scwin.tab_main_onchange = function (e) {
    scwin.f_selectTabMenu(tab_main.getSelectedTabIndex());
};

scwin.f_DefaultValue = function () {
    cnd_lc_seaair.setValue(scwin.seaair);
    cnd_lc_iogb.setValue(scwin.iogb);
    cnd_ed_ccano.setValue(scwin.ccaNo);

    if (cnd_lc_seaair.getValue() === "S") {
        chb_chkCwht.deleteItem(0);
        chb_chkCwht.addItem("1", "Measure", 0);
        chb_chkRate.deleteItem(0);
        chb_chkRate.addItem("1", "Freight Charge", 0);
        chb_chkOther.deleteItem(0);
        chb_chkOther.addItem("1", "Description", 0);
        chb_chkPcs.deleteItem(0);
        chb_chkPcs.addItem("1", "Package", 0);
        chb_chkDest.deleteItem(0);
        chb_chkDest.addItem("1", "Vessel/Voyage", 0);
        io_gb.setLabel(cnd_lc_iogb.getValue() === "I" ? "ETA" : "ETD");
    } else {
        chb_chkCwht.deleteItem(0);
        chb_chkCwht.addItem("1", "Chargeable Weight", 0);
        chb_chkRate.deleteItem(0);
        chb_chkRate.addItem("1", "Rate", 0);
        chb_chkOther.deleteItem(0);
        chb_chkOther.addItem("1", "Other Charge", 0);
        chb_chkPcs.deleteItem(0);
        chb_chkPcs.addItem("1", "Pieces", 0);
        chb_chkDest.deleteItem(0);
        chb_chkDest.addItem("1", "Destination", 0);
        io_gb.setLabel(cnd_lc_iogb.getValue() === "I" ? "Arrival Date" : "Onboard Date");
    }
};

//---------------------------------------------------------
//화면세팅
//---------------------------------------------------------
scwin.f_Set = function (gubun) {
    switch (gubun) {
        case "INIT": // 초기화
            $c.gus.cfDisableKeyData();
            $c.gus.cfDisableBtnOnly([btn_Print, btn_Create, btn_Update, btn_Cancel, btn_Save, btn_Delete]);
            $c.gus.cfEnableBtnOnly([btn_Create]);
            $c.gus.cfDisableObjects([cnd_lc_seaair, cnd_lc_iogb]);
            scwin.f_DisablePopUpObj();

            break;

        case "RETRIEVE": // 조회모드
            $c.gus.cfDisableKeyData();
            scwin.f_DisablePopUpObj();
            if (scwin.processFlag === "RETRIEVE") {
                $c.gus.cfDisableBtnOnly([btn_Save, btn_Cancel]);
                $c.gus.cfEnableBtnOnly([btn_Create, btn_Update, btn_Delete, btn_Print]);

                ds_ccano.setRowPosition(0);
            } else {
                $c.gus.cfDisableBtnOnly([btn_Cancel, btn_Update, btn_Save, btn_Delete, btn_Print]);
                $c.gus.cfEnableBtnOnly([btn_Create]);
            }
            break;

        case "CANCEL": // 취소
            scwin.f_Set("RETRIEVE");
            break;
        case "CREATE": // 신규
            $c.gus.cfEnableKeyData();
            scwin.f_EnablePopUpObj();
            $c.gus.cfDisableBtnOnly([btn_Create, btn_Update, btn_Delete]);
            $c.gus.cfEnableBtnOnly([btn_Save, btn_Cancel]);

            $c.gus.cfEnableObj(cnd_lc_iogb, true); // House

            $c.gus.cfEnableObj(ed_ccano, false); // CCA No
            $c.gus.cfEnableObj(ed_mblno, false); // Master
            $c.gus.cfEnableObj(lc_mmhno, false); // Master Consol

            $c.gus.cfEnableObj(ed_blno, true); // House
            $c.gus.cfEnableObj(lc_hmhno, true); // House Consol
            break;

        case "UPDATE":
            $c.gus.cfEnableKeyData();
            scwin.f_EnablePopUpObj();
            $c.gus.cfDisableBtnOnly([btn_Create, btn_Update, btn_Delete, btn_Print]);
            $c.gus.cfEnableBtnOnly([btn_Save, btn_Cancel]);

            $c.gus.cfEnableObj(ed_ccano, false); // CCA No
            $c.gus.cfEnableObj(ed_mblno, false); // Master
            $c.gus.cfEnableObj(lc_mmhno, false); // Master Consol

            $c.gus.cfEnableObj(ed_blno, true); // House
            $c.gus.cfEnableObj(lc_hmhno, true); // House Consol
            break;

        case "SAVE":
            $c.gus.cfDisableBtnOnly([btn_Save, btn_Cancel]);
            $c.gus.cfEnableBtnOnly([btn_Update, btn_Create, btn_Delete]);
            scwin.f_Set("RETRIEVE");
            break;

        case "DELETE":
            $c.gus.cfDisableBtnOnly([btn_Save, btn_Cancel]);
            $c.gus.cfEnableBtnOnly([btn_Create, btn_Update, btn_Delete]);
            scwin.f_Set("RETRIEVE");
            break;
    }
}

//-------------------------------------------------------------------------
// PopUp 이미지를 활성화 시킨다. 
//-------------------------------------------------------------------------
scwin.f_EnablePopUpObj = function () {
    $c.gus.cfEnableObjects([btn_to, ed_tocd, txt_tonm, btn_aseq, ed_aseq, txt_attn, ed_ondt, ed_isdt, btn_sgcd, ed_sgcd, txt_sgnm, ed_dest, ed_dscd1, ed_dscd2, ed_dscd3, btn_grdRowAdd, btn_grdRowDel]);

    // readOnly 필드 배경 흰색 유지
    [ed_idest, ed_idscd1, ed_iptcd1, ed_idscd2, ed_iptcd2, ed_idscd3, ed_iptcd3].forEach(function (comp) {
        comp.setStyle("background-color", "#ffffff");
    });
};

//-------------------------------------------------------------------------
// PopUp 이미지를 비활성화 시킨다. 
//-------------------------------------------------------------------------
scwin.f_DisablePopUpObj = function () {
    let targets = [btn_to, ed_tocd, txt_tonm, btn_aseq, ed_aseq, txt_attn,
        ed_ondt, ed_isdt, btn_sgcd, ed_sgcd, txt_sgnm,
        ed_dest, ed_dscd1, ed_dscd2, ed_dscd3];

    if (typeof btn_grdRowDel !== "undefined") targets.push(btn_grdRowAdd, btn_grdRowDel);

    $c.gus.cfDisableObjects(targets);

    // readOnly 필드 배경 회색 유지
    [ed_idest, ed_idscd1, ed_iptcd1, ed_idscd2, ed_iptcd2, ed_idscd3, ed_iptcd3].forEach(function (comp) {
        comp.setStyle("background-color", "");
    });

};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
    if (cnd_ed_ccano.getValue().trim() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Correction Notice No"]);
        cnd_ed_ccano.focus();
        return;
    }

    scwin.gubun = "Search";
    dma_search.set("ccano", cnd_ed_ccano.getValue().trim());
    dma_search.set("kcomcd", scwin.hid_kcomcd);

    if (ds_correctionNotice.getRowCount() > 0) {
        ds_correctionNotice.removeAll();
        ds_correctionNoticeFreightList.removeAll();
        ds_inCorrectionNoticeFreightList.removeAll();
        ds_blFreight.removeAll();
        ds_bl.removeAll();
        ds_hmhno.removeAll();
        ds_mmhno.removeAll();
    }

    await $c.sbm.execute(sbm_retrieve);
};

//-------------------------------------------------------------------------
// 신규
//-------------------------------------------------------------------------
scwin.f_Create = function () {
    ds_correctionNotice.removeAll();
    ds_correctionNoticeFreightList.removeAll();
    ds_inCorrectionNoticeFreightList.removeAll();
    ds_blFreight.removeAll();
    ds_bl.removeAll();
    ds_hmhno.removeAll();
    ds_mmhno.removeAll();

    lc_hmgb.focus();
    lc_hmgb.setValue("H");

    cnd_ed_ccano.setValue("");

    scwin.f_Set("CREATE");
    let intRowPosition = ds_correctionNotice.insertRow();

    ds_correctionNotice.setCellData(intRowPosition, "kcomcd", "DBEX"); // 법인코드
    ds_correctionNotice.setCellData(intRowPosition, "seaair", scwin.hid_seaair);
    ds_correctionNotice.setCellData(intRowPosition, "iogb", scwin.hid_iogb);
    ds_correctionNotice.setCellData(intRowPosition, "hmgb", lc_hmgb.getValue()); // lc_hmgb 기본값
    ds_correctionNotice.setRowPosition(intRowPosition);
};

//-------------------------------------------------------------------------
// 수정
//-------------------------------------------------------------------------
scwin.f_Update = function () {
    scwin.f_Set("UPDATE");
    //ed_tocd.focus();
};

//-------------------------------------------------------------------------
// 취소
//-------------------------------------------------------------------------
scwin.f_Undo = function () {
    // ds_correctionNotice.undoAll();
    // ds_correctionNoticeFreightList.undoAll();
    // ds_inCorrectionNoticeFreightList.undoAll();
    // scwin.f_Set("CANCEL");

    var wasCreate = (ds_correctionNotice.getRowCount() === 1 &&
        ds_correctionNotice.getRowStatus(0) === "C");

    ds_correctionNotice.undoAll();
    ds_correctionNoticeFreightList.undoAll();
    ds_inCorrectionNoticeFreightList.undoAll();

    if (wasCreate) {
        // CREATE 취소 → 초기 상태로 (필드 초기화)
        // ds_correctionNotice.setRowPosition(-1);   // ← 바인딩 강제 갱신
        ds_correctionNotice.removeAll();
        ds_correctionNoticeFreightList.removeAll();
        ds_inCorrectionNoticeFreightList.removeAll();

        scwin.processFlag = null;
        scwin.f_Set("INIT");
    } else {
        // UPDATE 취소 → 조회 상태 유지
        scwin.f_Set("CANCEL");
    }
};


//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
    if (ed_isdt.getValue().trim() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Issued Date"]);
        ed_isdt.focus();
        return;
    }

    if (await scwin.f_ReqFieldChk()) {
        let chk = await $c.win.confirm(E_MSG_CM_CRM_001);
        if (chk) {
            let rowPos = ds_correctionNotice.getRowPosition();
            if (lc_hmgb.getValue() == "H") {
                ds_correctionNotice.setCellData(rowPos, "mhno", lc_hmhno.getValue());
            } else {
                ds_correctionNotice.setCellData(rowPos, "mhno", lc_mmhno.getValue());
            }
            ds_correctionNotice.setCellData(rowPos, "isdt", ed_isdt.getValue());

            scwin.processFlag = "RETRIEVE";
            // processFlag = RETRIEVE; 인 경우 submit 완료 후 f_Set("RETRIEVE"); 호출
            ds_ccano.removeAll();

            await $c.sbm.execute(sbm_save);
        }
    }
};
//-------------------------------------------------------------------------
// 삭제
//-------------------------------------------------------------------------
scwin.f_Delete = async function () {
    let chk = await $c.win.confirm(E_MSG_CM_CRM_004); // 삭제하시겠습니까?
    if (chk) {
        let intRowPosition = ds_correctionNotice.getRowPosition();
        ds_correctionNotice.deleteRow(intRowPosition);

        scwin.processFlag = "RETRIEVE";   // ← 추가 (삭제 후 조회)

        ds_ccano.removeAll();

        await $c.sbm.execute(sbm_save);
    }
};

//-------------------------------------------------------------------------
// Validate check
//-------------------------------------------------------------------------
scwin.f_ReqFieldChk = async function () {
    let chk = await $c.gus.cfValidate([ed_tocd, ed_ondt, ed_isdt]);
    if (!chk) {
        return false;
    }
    return true;
};

//------------------------------------------------------------------------
// 조회 조건 필드 초기화
//------------------------------------------------------------------------
scwin.f_FieldClear = function () {
    $c.gus.cfInitObjects(tb_searchCondtion, null);
    cnd_ed_ccano.focus();
};



//-------------------------------------------------------------------------
// function name : f_Addrow
// function desc : 그리드 칼럼 추가
//-------------------------------------------------------------------------
scwin.f_Addrow = function () {
    scwin.f_AddRowWithParam(1); // udc_grdBtn1 >> 행추가  
}
scwin.f_AddRowWithParam = function (dsGubun) {
    let intRowPosition;
    switch (dsGubun) {
        case 1: //Correction NoticeFreight 운임 추가
            intRowPosition = ds_correctionNoticeFreightList.insertRow();
            ds_correctionNoticeFreightList.setCellData(intRowPosition, "kcomcd", scwin.hid_kcomcd); // 법인코드
            ds_correctionNoticeFreightList.setCellData(intRowPosition, "icgb", "C");   // ← 추가
            ds_correctionNoticeFreightList.setCellData(intRowPosition, "cwht", 0);
            ds_correctionNoticeFreightList.setCellData(intRowPosition, "rate", 0);
            ds_correctionNoticeFreightList.setCellData(intRowPosition, "charge", 0);

            break;

        case 2: // B/L Freight 운임 추가
            intRowPosition = ds_inCorrectionNoticeFreightList.insertRow();
            ds_inCorrectionNoticeFreightList.setCellData(intRowPosition, "kcomcd", scwin.hid_kcomcd); // 법인코드
            break;
    }
};


//-------------------------------------------------------------------------
// function name : f_delrow
// function desc : 그리드 칼럼 삭제
//-------------------------------------------------------------------------
scwin.f_Delrow = () => scwin.f_DelRowWithParam(1); // udc_grdBtn1 >> 행삭제
scwin.f_DelRowWithParam = function (dsGubun) {
    let intRowPosition;
    switch (dsGubun) {
        case 1: //Correction NoticeFreight 운임 삭제
            intRowPosition = ds_correctionNoticeFreightList.getRowPosition();
            if (ds_correctionNoticeFreightList.getRowStatusValue(intRowPosition) === 2) { // 신규생성 Row
                ds_correctionNoticeFreightList.removeRow(intRowPosition);
            } else {
                ds_correctionNoticeFreightList.deleteRow(intRowPosition);
                if (intRowPosition - 1 >= 0) {
                    ds_correctionNoticeFreightList.setRowPosition(intRowPosition - 1);
                }
            }
            break;
        case 2: // B/L Freight 운임 삭제
            intRowPosition = ds_inCorrectionNoticeFreightList.getRowPosition();
            if (ds_inCorrectionNoticeFreightList.getRowStatus(intRowPosition) === 2) {
                ds_inCorrectionNoticeFreightList.removeRow(intRowPosition);
            } else {
                ds_inCorrectionNoticeFreightList.deleteRow(intRowPosition);
                if (intRowPosition - 1 >= 0) {
                    ds_inCorrectionNoticeFreightList.setRowPosition(intRowPosition - 1);
                }
            }
            break;
    }
};

//-------------------------------------------------------------------------
// 팝업
//-------------------------------------------------------------------------
scwin.f_PopUp = function (disGubun, chgGubun, img) {
    switch (disGubun) {
        case 1:
            //거래처 팝업(Search Partner)
            udc_to.setSelectId("retrieveEngClntInfo");
            udc_to.ilCommonPopUp(scwin.udc_to_callBackFunc,
                ed_tocd.getValue().trim(),
                txt_tonm.getValue(),
                chgGubun,
                '5',
                'To',
                '140,300,300',
                null,
                null,
                '500',
                '500',
                null,
                null,
                null,
                'F',
                'To Search,To Code,To Name');
            break;
        case 2:
            // 거래처 담당자(To)
            if (img !== "img") {
                if (txt_attn.getValue() != "") {
                    break;
                }
            }
            let pParam = ed_tocd.getValue().trim();
            udc_aseq.setSelectId("retrieveClntPicInfo");
            udc_aseq.ilCommonPopUp(scwin.udc_aseq_callBackFunc,
                ed_aseq.getValue().trim(),
                txt_attn.getValue(),
                chgGubun,
                '4',
                "PIC",
                '100,350',
                null,
                pParam,
                '500',
                '500',
                null,
                null,
                null,
                "T",
                null);
            break;
        case 3:
            // 사원 관리 코드
            udc_sg.setSelectId("retrieveEmpInfo");
            udc_sg.ilCommonPopUp(
                scwin.udc_sg_callBackFunc,
                ed_sgcd.getValue().trim(),
                txt_sgnm.getValue(),
                chgGubun,
                '4',
                "Signature",
                '100,350',
                null,
                '',
                '500',
                '500',
                null,
                null,
                null,
                "T",
                null);
            break;

        default:
            break;
    }
};

scwin.udc_to_callBackFunc = function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_tocd, txt_tonm);
};

scwin.udc_aseq_callBackFunc = function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_aseq, txt_attn);
};

scwin.udc_sg_callBackFunc = function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_sgcd, txt_sgnm);
};

//-------------------------------------------------------------------------
// 팝업
//-------------------------------------------------------------------------
scwin.f_PopUp2 = function (disGubun, chgGubun, fieldCode, fieldName) {
    switch (disGubun) {
        case 3:
            //Departure Port
            let seaairVal = cnd_lc_seaair.getValue().trim();
            let code = "";
            let name = "";

            if (fieldCode != "" && fieldCode != null) {
                code = fieldCode.getValue().trim();
            }
            if (fieldName != "" && fieldName != null) {
                name = fieldName.getValue();
            }

            if (seaairVal === "S") {
                udc_ccd_depPort.setSelectId("retrievePortInfo");
                udc_ccd_depPort.cfCommonPopUp(
                    scwin.callbackPopUp2_port,
                    code,
                    name,
                    chgGubun,
                    '5',                            // 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                    null,                 			// Title순서	                                                           
                    '140,300',                      // 보여주는 각 컬럼들의 폭	                                               
                    null,                           // 컬럼중에서 숨기는	컬럼 지정	                                       
                    null,                           // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능              
                    '500',                          // POP-UP뛰을때 원도우의	사용자 정의	폭                                 
                    '500',                          // POP-UP뛰을때 우도우의	사용자 정의	높이	                           
                    null,                           // 윈도우 위치 Y좌표	                                                   
                    null,                           // 윈도우 위치 X좌표                                                       
                    null,                           // 중복체크여부	("F")                                                      
                    'F',                            // 전체검색허용여부	("F")                                                  
                    'Departure Port Search,Port Code,Port Name');                          // POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")  
            } else {
                udc_ilcomCode_Grid.setSelectId("retrieveAirPortCode");
                udc_ilcomCode_Grid.ilCommonPopUp(
                    scwin.callbackPopUp2_port,
                    code,
                    name,
                    chgGubun,
                    '5',                            // 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                    'Port Code,Port Name',          // Title순서	                                                           
                    '140,300',                      // 보여주는 각 컬럼들의 폭	                                               
                    null,                           // 컬럼중에서 숨기는	컬럼 지정	                                       
                    null,                           // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능              
                    '500',                          // POP-UP뛰을때 원도우의	사용자 정의	폭                                 
                    '500',                          // POP-UP뛰을때 우도우의	사용자 정의	높이	                           
                    null,                           // 윈도우 위치 Y좌표	                                                   
                    null,                           // 윈도우 위치 X좌표                                                       
                    null,                           // 중복체크여부	("F")                                                      
                    'F',                            // 전체검색허용여부	("F")                                                  
                    'Departure Port Search,Port Code,Port Name');                          // POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            }

            scwin._popUp2FieldCode = fieldCode;
            break;
        default:
            break;
    }
};

scwin.callbackPopUp2_port = function (rtnList) {
    if (scwin._popUp2FieldCode != null && scwin._popUp2FieldCode != "") {
        $c.gus.cfSetReturnValue(rtnList, scwin._popUp2FieldCode);
    }
};

scwin.f_Chk = function (disGubun) {
    // getValue() >> 1: checked , 0: unchecked
    switch (disGubun) {
        case 1: // G/Weight
            if (chb_chkGwht.getValue() === "1") {
                scwin.cfViewTab(0);
                if (ds_bl.getRowCount() > 0) {
                    txa_mark1.setValue(txa_mark1.getValue() + "GROSS W/T : " + ds_bl.getCellData(0, "gwgt") + "\r\n");
                    txa_mark2.setValue(txa_mark2.getValue() + "GROSS W/T : " + "\r\n");
                }
            }
            break;
        case 2: //Chargeable Weight / Rate
            if (chb_chkCwht.getValue() === "1" || chb_chkRate.getValue() === "1") {
                if (ds_blFreight.getRowCount() > 0 && ds_correctionNoticeFreightList.getRowCount() < 1) {
                    scwin.cfViewTab(1);
                    for (let i = 0; i < ds_blFreight.getRowCount(); i++) {
                        let rowOrd = ds_correctionNoticeFreightList.insertRow();
                        ds_correctionNoticeFreightList.setCellData(rowOrd, "kcomcd", ds_blFreight.getCellData(i, "kcomcd"));
                        ds_correctionNoticeFreightList.setCellData(rowOrd, "ccano", ds_blFreight.getCellData(i, "ccano"));
                        ds_correctionNoticeFreightList.setCellData(rowOrd, "icgb", "C");
                        ds_correctionNoticeFreightList.setCellData(rowOrd, "fcode", ds_blFreight.getCellData(i, "fcode"));
                        ds_correctionNoticeFreightList.setCellData(rowOrd, "fdesc", ds_blFreight.getCellData(i, "fdesc"));
                        ds_correctionNoticeFreightList.setCellData(rowOrd, "pcgb", ds_blFreight.getCellData(i, "pcgb"));
                        ds_correctionNoticeFreightList.setCellData(rowOrd, "cwht", ds_blFreight.getCellData(i, "cwht"));
                        ds_correctionNoticeFreightList.setCellData(rowOrd, "rate", ds_blFreight.getCellData(i, "rate"));
                        ds_correctionNoticeFreightList.setCellData(rowOrd, "charge", ds_blFreight.getCellData(i, "charge"));

                        let rowOrd2 = ds_inCorrectionNoticeFreightList.insertRow();
                        ds_inCorrectionNoticeFreightList.setCellData(rowOrd2, "kcomcd", ds_blFreight.getCellData(i, "kcomcd"));
                        ds_inCorrectionNoticeFreightList.setCellData(rowOrd2, "ccano", ds_blFreight.getCellData(i, "ccano"));
                        ds_inCorrectionNoticeFreightList.setCellData(rowOrd2, "icgb", ds_blFreight.getCellData(i, "icgb"));
                        ds_inCorrectionNoticeFreightList.setCellData(rowOrd2, "fcode", ds_blFreight.getCellData(i, "fcode"));
                        ds_inCorrectionNoticeFreightList.setCellData(rowOrd2, "fdesc", ds_blFreight.getCellData(i, "fdesc"));
                        ds_inCorrectionNoticeFreightList.setCellData(rowOrd2, "pcgb", ds_blFreight.getCellData(i, "pcgb"));
                        ds_inCorrectionNoticeFreightList.setCellData(rowOrd2, "cwht", ds_blFreight.getCellData(i, "cwht"));
                        ds_inCorrectionNoticeFreightList.setCellData(rowOrd2, "rate", ds_blFreight.getCellData(i, "rate"));
                        ds_inCorrectionNoticeFreightList.setCellData(rowOrd2, "charge", ds_blFreight.getCellData(i, "charge"));
                    }
                }
            }
            break;

        case 3: //Pieces
            if (chb_chkPcs.getValue() === "1") {
                scwin.cfViewTab(0);
                if (ds_bl.getRowCount() > 0) {
                    txa_mark1.setValue(txa_mark1.getValue() + "PIECES : " + ds_bl.getCellData(0, "pkg") + "\r\n");
                    txa_mark2.setValue(txa_mark2.getValue() + "PIECES : " + "\r\n");
                }
            }
            break;
        case 4: // Consignee
            if (chb_chkCn.getValue() === "1") {
                scwin.cfViewTab(0);
                if (ds_bl.getRowCount() > 0) {
                    txa_mark1.setValue(txa_mark1.getValue() + "Consignee : " + "\r\n   " + ds_bl.getCellData(0, "cnnm1") + "\r\n");
                    if (ds_bl.getCellData(0, "cnnm2") != "") {
                        txa_mark1.setValue(txa_mark1.getValue() + "   " + ds_bl.getCellData(0, "cnnm2") + "\r\n");
                    }
                    if (ds_bl.getCellData(0, "cnnm3") != "") {
                        txa_mark1.setValue(txa_mark1.getValue() + "   " + ds_bl.getCellData(0, "cnnm3") + "\r\n");
                    }
                    if (ds_bl.getCellData(0, "cnnm4") != "") {
                        txa_mark1.setValue(txa_mark1.getValue() + "   " + ds_bl.getCellData(0, "cnnm4") + "\r\n");
                    }
                    if (ds_bl.getCellData(0, "cnnm5") != "") {
                        txa_mark1.setValue(txa_mark1.getValue() + "   " + ds_bl.getCellData(0, "cnnm5") + "\r\n");
                    }
                    txa_mark2.setValue(txa_mark2.getValue() + "Consignee : " + "\r\n   ");
                }
            }
            break;

        case 5: // Shipper
            if (chb_chkSh.getValue() === "1") {
                scwin.cfViewTab(0);
                if (ds_bl.getRowCount() > 0) {
                    txa_mark1.setValue(txa_mark1.getValue() + "Shipper : " + "\r\n   " + ds_bl.getCellData(0, "shnm1") + "\r\n");
                    if (ds_bl.getCellData(0, "shnm2") != "") {
                        txa_mark1.setValue(txa_mark1.getValue() + "   " + ds_bl.getCellData(0, "shnm2") + "\r\n");
                    }
                    if (ds_bl.getCellData(0, "shnm3") != "") {
                        txa_mark1.setValue(txa_mark1.getValue() + "   " + ds_bl.getCellData(0, "shnm3") + "\r\n");
                    }
                    if (ds_bl.getCellData(0, "shnm4") != "") {
                        txa_mark1.setValue(txa_mark1.getValue() + "   " + ds_bl.getCellData(0, "shnm4") + "\r\n");
                    }
                    if (ds_bl.getCellData(0, "shnm5") != "") {
                        txa_mark1.setValue(txa_mark1.getValue() + "   " + ds_bl.getCellData(0, "shnm5") + "\r\n");
                    }
                    txa_mark2.setValue(txa_mark2.getValue() + "Shipper : " + "\r\n   ");
                }
            }
            break;

        case 6: //Destination
            if (chb_chkDest.getValue() === "1") {
                scwin.cfViewTab(0);
                if (ds_bl.getRowCount() > 0) {
                    ed_idest.setValue(ds_bl.getCellData(0, "dpcd")); // Departure
                    ed_idscd1.setValue(ds_bl.getCellData(0, "dscd1")); // TO-1
                    ed_iptcd1.setValue(ds_bl.getCellData(0, "ptcd1")); // First Carrier
                    ed_idscd2.setValue(ds_bl.getCellData(0, "dscd2")); // To-2
                    ed_iptcd2.setValue(ds_bl.getCellData(0, "ptcd2")); // By-1
                    ed_idscd3.setValue(ds_bl.getCellData(0, "dscd3")); // To-3
                    ed_iptcd3.setValue(ds_bl.getCellData(0, "ptcd3")); // By-2
                }
            }
            break;

        case 7: // Notify
            if (chb_chkNt.getValue() === "1") {
                scwin.cfViewTab(0);
                if (ds_bl.getRowCount() > 0) {
                    txa_mark1.setValue(txa_mark1.getValue() + "Notify  : " + "\r\n   " + ds_bl.getCellData(0, "ntnm1") + "\r\n");
                    if (ds_bl.getCellData(0, "ntnm2") != "") {
                        txa_mark1.setValue(txa_mark1.getValue() + "   " + ds_bl.getCellData(0, "ntnm2") + "\r\n");
                    }
                    if (ds_bl.getCellData(0, "ntnm3") != "") {
                        txa_mark1.setValue(txa_mark1.getValue() + "   " + ds_bl.getCellData(0, "ntnm3") + "\r\n");
                    }
                    if (ds_bl.getCellData(0, "ntnm4") != "") {
                        txa_mark1.setValue(txa_mark1.getValue() + "   " + ds_bl.getCellData(0, "ntnm4") + "\r\n");
                    }
                    if (ds_bl.getCellData(0, "ntnm5") != "") {
                        txa_mark1.setValue(txa_mark1.getValue() + "   " + ds_bl.getCellData(0, "ntnm5") + "\r\n");
                    }
                    txa_mark2.setValue(txa_mark2.getValue() + "Notify  : " + "\r\n   ");
                }
            }
            break;

        default:
            break;
    }
};

