// 조회 결과
scwin.sbm_retrieve_submitdone = async function (e) {
    if (ds_correctionNotice.getRowCount() == 0) {
        await $c.gus.cfAlertMsg(E_MSG_CM_WRN_002);
        scwin.processFlag = "INIT";
        scwin.f_Set("INIT");
    } else {
        ds_correctionNotice.setRowPosition(0); // 전체 바인딩 자동 반영
        scwin.lc_hmgb_onchange(); // 바인딩 후 수동 실행

        let strClntNo = "";
        if (lc_hmgb.getValue() === "H") {
            strClntNo = ed_blno.getValue().trim();
            if (strClntNo.length > 0) {
                let param1 = strClntNo;
                scwin.f_loadHmhno(param1);
            } else {
                ds_hmhno.removeAll();
            }
        } else {
            strClntNo = ed_mblno.getValue().trim();
            if (strClntNo.length > 0) {
                scwin.f_loadMmhno(strClntNo, scwin.f_MasterInfo);
            } else {
                ds_mmhno.removeAll();
            }
        }

        c_totalCnt.setValue(ds_correctionNoticeFreightList.getRowCount());
        inc_totalCnt.setValue(ds_inCorrectionNoticeFreightList.getRowCount());
    }
};

scwin.sbm_save_submitdone = async function (e) {
    // responseJSON에서 resultDataSet 추출
    var resultDataSet = e.responseJSON.resultDataSet;

    if (!resultDataSet || resultDataSet.length === 0) {
        return;
    }

    // 첫번째 행 = Result (성공/실패 여부)
    var result = resultDataSet[0];
    if (result.Msg === "SUCC") {
        // 성공
        await $c.gus.cfAlertMsg(E_MSG_CM_INF_001);

        // 신규 저장 후 새 CCANO를 ds_correctionNotice에 갱신
        if (ds_ccano.getRowCount() > 0) {
            let newCcano = ds_ccano.getCellData(0, "ccano");
            if (newCcano && ds_correctionNotice.getRowCount() > 0) {
                let rowPos = ds_correctionNotice.getRowPosition();
                ds_correctionNotice.setCellData(rowPos, "ccano", newCcano);

                cnd_ed_ccano.setValue(newCcano);
                scwin.f_Retrieve();

            } else if (newCcano === "") {
                ds_correctionNotice.setRowPosition(-1);

                // 삭제 완료 후 전체 데이터 초기화
                ds_correctionNotice.removeAll();
                ds_correctionNoticeFreightList.removeAll();
                ds_inCorrectionNoticeFreightList.removeAll();
                ds_blFreight.removeAll();
                ds_bl.removeAll();
                ds_hmhno.removeAll();
                ds_mmhno.removeAll();

            }
        }
    }

    $c.gus.cfDisableBtnOnly([btn_Cancel, btn_Save]);
    gr_correctFreight.refreshColumn(0);

    scwin.processFlag = "RETRIEVE";
    scwin.f_Set("RETRIEVE");
};

scwin.sbm_retrieveBl_submitdone = async function (e) {
    if (ds_bl.getRowCount() == 0) {
        await $c.win.alert("BL 정보가 없습니다.");
        scwin.processFlag = "INIT";
        scwin.f_Set("INIT");
    } else {
        ds_correctionNotice.removeAll();
        ds_correctionNotice.insertRow();

        let i = ds_correctionNotice.getRowPosition();
        let k = ds_bl.getRowPosition() ?? 0;
        ds_correctionNotice.setCellData(i, "kcomcd", ds_bl.getCellData(k, "kcomcd"));

        if (ds_bl.getCellData(k, "hmgb") == "H") {
            ds_correctionNotice.setCellData(i, "blno", ds_bl.getCellData(k, "blno"));
            ds_correctionNotice.setCellData(i, "mhno", lc_hmhno.lo_100_03_03b.xmlgetValue());
        } else {
            ds_correctionNotice.setCellData(i, "mblno", ds_bl.getCellData(k, "blno"));
            ds_correctionNotice.setCellData(i, "mhno", lc_mmhno.getValue());
        }
        ds_correctionNotice.setCellData(i, "iogb", cnd_lc_iogb.getValue());
        ds_correctionNotice.setCellData(i, "seaair", cnd_lc_seaair.getValue());
        ds_correctionNotice.setCellData(i, "hmgb", ds_bl.getCellData(k, "hmgb"));
        ds_correctionNotice.setCellData(i, "cucd", ds_bl.getCellData(k, "cucd"));
        ds_correctionNotice.setCellData(i, "ondt", ds_bl.getCellData(k, "stdt"));

        setTimeout(function () {
            ds_correctionNotice.setRowPosition(0);
        });
    }
};

// submit 완료 후 다음 처리 실행하기 위해 callback 구현
scwin.hmhnoCallback = null;

scwin.f_loadHmhno = function (param, callback) {
    scwin.hmhnoCallback = callback || null;
    dma_hmhno_search.set("sysCd", "ilCommonEBC");
    dma_hmhno_search.set("queryId", "retriveAirHouseMhnoListCombo");
    dma_hmhno_search.set("param1", param);
    $c.sbm.execute(sbm_hmhno);
}

scwin.mmhnoCallback = null;

scwin.f_loadMmhno = function (param, callback) {
    scwin.mmhnoCallback = callback || null;
    dma_mmhno_search.set("sysCd", "ilCommonEBC");
    dma_mmhno_search.set("queryId", "retriveAirMasterMhnoListCombo")
    dma_mmhno_search.set("param1", param);
