scwin.ds_correctionNotice_onrowpositionchange = function (rowIndex, oldRow) {
    let vRowPosition = ds_correctionNotice.getRowPosition();
    let vRowStatus = ds_correctionNotice.getRowStatusValue(vRowPosition);

    if (vRowPosition >= 0) {
        if (vRowStatus === 0) { // 원본 상태 
            $c.gus.cfDisableBtnOnly([btn_Print, btn_Create, btn_Update, btn_Cancel, btn_Save, btn_Delete]);
            $c.gus.cfEnableBtnOnly([btn_Print, btn_Create, btn_Update, btn_Delete]);
            scwin.processFlag = "RETRIEVE";
        } else if (vRowStatus === 2) { // 신규 생성
            scwin.f_Set("CREATE");
        } else if (vRowStatus === 1) { // 업데이트(갱신)
            scwin.f_Set("UPDATE");
        }
    } else {
        scwin.f_Set("INIT");
        scwin.processFlag = "INIT";
    }
};

